    archive_present = bool(archive.get('exists') and int(archive.get('size_bytes') or 0) > 0)
    parts_present = bool(parts_dir.get('manifest_exists') and int(parts_dir.get('part_file_count') or 0) > 0)
    bundle_mode = config.get('prerequisite_bundle_mode') or 'archive'
    if bundle_mode == 'split':
        prerequisite_transfer_ready = parts_present
    elif bundle_mode == 'both':
        prerequisite_transfer_ready = archive_present and parts_present
    else:
        prerequisite_transfer_ready = archive_present
    metadata_present = bool(metadata and metadata.get('exists'))
    metadata_trusted_table = json_field(metadata_relative, 'trusted_table') if metadata_relative else None
